const devices = $input.item.json;
const input = $('Send SMS Webhook').item.json;
const to = input.to;

const online = Array.isArray(devices) 
  ? devices.filter(d => d.isOnline && d.isEnabled)
  : [];

if (online.length === 0) {
  throw new Error('No phones online');
}

const areaCode = to.replace(/[^0-9]/g, '').substring(1, 4);

const matchArea = online.find(d => 
  d.phoneNumber && d.phoneNumber.replace(/[^0-9]/g,'').substring(1,4) === areaCode
);

const selected = matchArea || online[Math.floor(Math.random() * online.length)];

return {
  deviceId: selected._id || selected.id,
  devicePhone: selected.phoneNumber,
  to: input.to,
  message: input.message,
  contact_id: input.contact_id,
  campaign_id: input.campaign_id,
  selected_reason: matchArea ? 'area_code_match' : 'round_robin'
};

const result = $input.item.json;
const input = $('Select Best Phone').item.json;
const success = result.success !== false;

return {
  success,
  to: input.to,
  from: input.devicePhone,
  device_id: input.deviceId,
  contact_id: input.contact_id,
  campaign_id: input.campaign_id,
  message_id: result.id || result._id,
  sent_at: new Date().toISOString()
};
